mapper.select:
select cos.id, cos.create_time, cos.order_no, cos.user_id, cos.merchant_id, cos.user_address_id, cos.order_products, cos.total_price, cos.order_welfares, cos.deliver_price, cos.real_price, cos.state, cos.payment_type, cos.payment_state, cos.update_time, cos.remarks, cmi.merchant_name, cmi.logo, col.logistics_no, col.logistics_name, cua.concat_person, cua.contact_phone, cua.address, concat(c1.city_name,c2.city_name,c3.city_name,cua.address) as fullAddress from cm_order_shopping cos left join cm_merchant_info cmi on cos.merchant_id = cmi.id left join cm_order_logistics col on cos.order_no = col.shopping_order_no left join cm_user_address cua on cos.user_address_id = cua.id left join city_code c1 on cua.province_code = c1.city_id left join city_code c2 on cua.city_code = c1.city_id left join city_code c3 on cua.country_code = c1.city_id where cos.deleted = '0'
and cos.user_id = #{param.userId}
and cos.payment_state = #{param.paymentState}
and cos.state = #{param.state}
order by cos.update_time desc, cos.create_time desc

select id, create_time, order_no, user_id, merchant_id, user_address_id, order_products, order_welfares,
       total_price, deliver_price, real_price, state, payment_type, payment_state, update_time, deleted, remarks
from cm_order_shopping where order_no = #{orderNo}
